import React, { useMemo, useRef, useState } from "react";
import { useNavigate } from "react-router-dom";

const ORKIO_BALL = "data:image/png;base64,";

function getWelcomeMessage() {
  return {
    intro: "Hello there. I’m Orkio.",
    body:
      "I help transform complexity into direction — with clarity, structure and trusted intelligence.",
    question:
      "What is the clearest strategic outcome you want AI to help you deliver?",
  };
}

export default function PublicChatWidget() {
  const nav = useNavigate();
  const [open, setOpen] = useState(false);
  const [typed, setTyped] = useState("");
  const [speaking, setSpeaking] = useState(false);
  const utteranceRef = useRef(null);

  const content = useMemo(() => getWelcomeMessage(), []);

  function speakAvatar() {
    try {
      if (!("speechSynthesis" in window)) return;
      window.speechSynthesis.cancel();

      const text = `${content.intro} ${content.body} ${content.question}`;
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = "en-US";
      utterance.rate = 0.88;
      utterance.pitch = 0.72;
      utterance.volume = 1;

      const voices = window.speechSynthesis.getVoices?.() || [];
      const preferred =
        voices.find((v) => /en-US/i.test(v.lang) && /david|matthew|fred|daniel|lee/i.test(v.name)) ||
        voices.find((v) => /en-US/i.test(v.lang)) ||
        voices[0];

      if (preferred) utterance.voice = preferred;

      utterance.onstart = () => setSpeaking(true);
      utterance.onend = () => setSpeaking(false);
      utterance.onerror = () => setSpeaking(false);

      utteranceRef.current = utterance;
      window.speechSynthesis.speak(utterance);
    } catch {
      setSpeaking(false);
    }
  }

  function openWidget() {
    setOpen(true);
    setTimeout(() => {
      speakAvatar();
    }, 120);
  }

  function goToSignup() {
    setOpen(false);
    nav("/auth");
  }

  return (
    <>
      {!open ? (
        <button
          type="button"
          onClick={openWidget}
          className="fixed bottom-5 right-5 z-50 rounded-2xl border border-white/15 bg-[linear-gradient(135deg,#37C5FF,#7D6BFF)] px-5 py-4 text-sm font-extrabold uppercase tracking-[0.12em] text-[#0B0F14] shadow-[0_18px_40px_rgba(55,197,255,0.22)]"
        >
          Talk with Orkio
        </button>
      ) : null}

      {open ? (
        <div className="fixed inset-x-4 bottom-4 z-50 ml-auto w-[min(100%,440px)] rounded-[28px] border border-white/10 bg-[#070910]/95 text-white shadow-[0_30px_90px_rgba(0,0,0,0.5)] backdrop-blur">
          <div className="flex items-start justify-between gap-4 border-b border-white/10 p-4">
            <div className="flex items-center gap-3">
              <img
                src={ORKIO_BALL}
                alt="Orkio"
                className="h-12 w-12 rounded-full object-contain bg-[#0B0F14] p-1 ring-1 ring-[#37C5FF]/30"
              />
              <div>
                <div className="text-base font-black leading-tight">Private access required</div>
                <div className="text-sm text-white/60">Enter through the official signup flow</div>
              </div>
            </div>

            <button
              type="button"
              onClick={() => setOpen(false)}
              className="rounded-xl border border-white/15 bg-white/5 px-3 py-2 text-sm font-semibold text-white/80 hover:bg-white/10"
            >
              Close
            </button>
          </div>

          <div className="space-y-4 p-4">
            <div className="rounded-[22px] border border-white/10 bg-white/[0.04] p-4 leading-7 text-white/90">
              <div>{content.intro}</div>
              <div className="mt-4">{content.body}</div>
              <div className="mt-2">{content.question}</div>
            </div>

            <div className="rounded-[22px] border border-[#37C5FF]/20 bg-[#0B0F14] p-4">
              <div className="text-sm text-white/75">
                Continue through the official access flow and Orkio will be ready for you inside the platform.
              </div>
              <div className="mt-4 flex flex-wrap gap-3">
                <button
                  type="button"
                  onClick={goToSignup}
                  className="rounded-2xl bg-[linear-gradient(135deg,#37C5FF,#7D6BFF)] px-4 py-3 text-sm font-extrabold uppercase tracking-[0.12em] text-[#0B0F14] shadow-[0_16px_34px_rgba(55,197,255,0.22)]"
                >
                  Go to signup
                </button>
                <button
                  type="button"
                  onClick={speakAvatar}
                  className="rounded-2xl border border-white/15 bg-white/5 px-4 py-3 text-sm font-bold text-white/85 hover:bg-white/10"
                >
                  {speaking ? "Speaking..." : "Hear Orkio again"}
                </button>
              </div>
            </div>

            <div className="flex items-center gap-3 rounded-[20px] border border-white/10 bg-white/[0.03] p-3">
              <input
                value={typed}
                onChange={(e) => setTyped(e.target.value)}
                placeholder="Private chat starts after signup"
                className="min-w-0 flex-1 bg-transparent text-sm text-white/75 outline-none placeholder:text-white/35"
                readOnly
              />
              <button
                type="button"
                onClick={goToSignup}
                className="rounded-xl bg-[linear-gradient(135deg,#7D6BFF,#37C5FF)] px-4 py-2 text-sm font-black text-[#0B0F14]"
              >
                Signup
              </button>
            </div>
          </div>
        </div>
      ) : null}
    </>
  );
}
